#!/bin/bash
set -e
if echo dGVzdA== | base64 -D >/dev/null 2>&1; then B64FLAG="-D"; else B64FLAG="-d"; fi
mkdir -p components pages
echo 'Writing components/Nav.js...'
base64 $B64FLAG << 'B64_GAL_1' > components/Nav.js

B64_GAL_1
echo 'Writing components/Footer.js...'
base64 $B64FLAG << 'B64_GAL_2' > components/Footer.js

B64_GAL_2
echo 'Writing pages/gallery.js...'
base64 $B64FLAG << 'B64_GAL_3' > pages/gallery.js

B64_GAL_3
echo 'Gallery files written successfully.'
